#include <vector>
#include <algorithm>

using namespace std;

vector<long long> solve(long long n) {
    vector<long long> result;
    long long power = 1; // Represents 10^k, starting with 10^0 = 1

    while (n > 0) {
        long long digit = n % 10;
        if (digit != 0) {
            result.push_back(digit * power);
        }
        n /= 10;
        power *= 10;
    }

    // The result is built in reverse order (smallest to largest), so reverse it
    reverse(result.begin(), result.end());

    return result;
}
